```

<img width="1089" height="799" alt="Image" src="https://github.com/user-attachments/assets/a02d5f2a-6392-421e-bad6-d131f8b81146" />

All of these values and calculations match exactly those that were logged directly from the Godot functions.  They are just made in Python for easy reproducibility.

```Python
# FFT routine, (C)1996 S.M.Bernsee.
def fftb(fftBuffer, sign = -1):
    fftFrameSize = len(fftBuffer)//2

    #float wr, wi, arg, *p1, *p2, temp;
    #float tr, ti, ur, ui, *p1r, *p1i, *p2r, *p2i;
    #long i, bitm, j, le, le2, k;

    for i in range(2, 2 * fftFrameSize - 2, 2):
        bitm = 2
        j = 0
        while bitm < 2 * fftFrameSize:
            if (i & bitm):
                j += 1
            j <<= 1
            bitm <<= 1
        if i < j:
            p1 = i;
            p2 = j;
            temp = fftBuffer[p1];
            fftBuffer[p1] = fftBuffer[p2]
            p1 += 1
            fftBuffer[p2] = temp
            p2 += 1
            temp = fftBuffer[p1]
            fftBuffer[p1] = fftBuffer[p2]
            fftBuffer[p2] = temp

    logN = int(math.log(fftFrameSize)/math.log(2.)+.5)
    le = 2
    for k in range(logN):
        le <<= 1;
        le2 = le >> 1;
        ur = 1.0;
        ui = 0.0;
        arg = math.pi / (le2 >> 1);
        wr = math.cos(arg);
        wi = sign * math.sin(arg);
        for j in range(0, le2, 2):
            p1r = j;
            p1i = p1r + 1;
            p2r = p1r + le2;
            p2i = p2r + 1;
            for i in range(j, 2 * fftFrameSize, le):
                tr = fftBuffer[p2r] * ur - fftBuffer[p2i] * ui;
                ti = fftBuffer[p2r] * ui + fftBuffer[p2i] * ur;
                fftBuffer[p2r] = fftBuffer[p1r] - tr;
                fftBuffer[p2i] = fftBuffer[p1i] - ti;
                fftBuffer[p1r] += tr;
                fftBuffer[p1i] += ti;
                p1r += le;
                p1i += le;
                p2r += le;
                p2i += le;
            tr = ur * wr - ui * wi;
            ui = ur * wi + ui * wr;
            ur = tr;

    return fftBuffer

# Convert to and from complex domain.
def Rfft(yval):
    fftBuffer = [ ]
    for y in yval:
        fftBuffer.append(y)
        fftBuffer.append(0.0)

    fftR = fftb(fftBuffer, sign = -1)
    res = [ ]
    for i in range(len(yval)):
        res.append(math.hypot(fftR[i*2], fftR[i*2+1]))
    return res
```




